from pydantic import BaseModel, Field, field_validator
from typing import Literal
import re

class UserMessage(BaseModel):
    role: Literal["user"] = "user"
    content: str = Field(..., min_length=1, max_length=8192)
    session_id: str = Field(..., pattern=r"^[a-f0-9]{32}$")

    @field_validator("content")
    @classmethod
    def strip_null_bytes(cls, v: str) -> str:
        return v.replace("\x00", "")

class ToolResult(BaseModel):
    tool_use_id: str
    content: str | list[dict]
    is_error: bool = False

# At the API boundary
from fastapi import FastAPI, HTTPException
from pydantic import ValidationError

app = FastAPI()

@app.post("/chat")
async def chat_endpoint(raw: dict):
    try:
        msg = UserMessage(**raw)
    except ValidationError as exc:
        raise HTTPException(status_code=422, detail=exc.errors())
    # msg is now guaranteed to be valid
    return await run_agent(msg)

import anthropic
import json

def normalise_tool_result(result: object, tool_use_id: str, max_chars: int = 4096) -> dict:
    """Convert a raw tool return value into a valid tool_result message block."""
    if isinstance(result, str):
        content = result
    elif isinstance(result, (dict, list)):
        content = json.dumps(result, default=str)
    elif isinstance(result, Exception):
        return {
            "type": "tool_result",
            "tool_use_id": tool_use_id,
            "is_error": True,
            "content": f"Tool error: {type(result).__name__}: {result}",
        }
    else:
        content = str(result)

    # Truncate overly long results to stay inside the context window
    if len(content) > max_chars:
        content = content[:max_chars] + f"\n[truncated — {len(content) - max_chars} chars omitted]"

    return {
        "type": "tool_result",
        "tool_use_id": tool_use_id,
        "content": content,
    }

def build_user_tool_results(tool_use_blocks, results: dict) -> dict:
    """Build the user-role message that returns all tool results to the model."""
    content = [
        normalise_tool_result(results[b.id], b.id)
        for b in tool_use_blocks
        if b.id in results
    ]
    return {"role": "user", "content": content}

import base64, mimetypes
from pathlib import Path

ALLOWED_IMAGE_TYPES = {"image/jpeg", "image/png", "image/gif", "image/webp"}
MAX_IMAGE_BYTES = 5 * 1024 * 1024   # 5 MB

def prepare_image_block(file_bytes: bytes, filename: str) -> dict:
    mime, _ = mimetypes.guess_type(filename)
    if mime not in ALLOWED_IMAGE_TYPES:
        raise ValueError(f"Unsupported image type: {mime}")
    if len(file_bytes) > MAX_IMAGE_BYTES:
        raise ValueError(f"Image exceeds 5 MB limit ({len(file_bytes)} bytes)")

    return {
        "type": "image",
        "source": {
            "type": "base64",
            "media_type": mime,
            "data": base64.standard_b64encode(file_bytes).decode(),
        },
    }

def build_multimodal_message(text: str, image_bytes: bytes | None, filename: str | None) -> dict:
    content = [{"type": "text", "text": text}]
    if image_bytes and filename:
        content.append(prepare_image_block(image_bytes, filename))
    return {"role": "user", "content": content}

from pydantic import BaseModel
from typing import Literal
import anthropic, json

client = anthropic.Anthropic()

class IntentSchema(BaseModel):
    intent: Literal["create_task", "update_task", "delete_task", "list_tasks", "unknown"]
    entity_id: str | None = None   # task ID when updating or deleting
    parameters: dict = {}

INTENT_TOOL = {
    "name": "classify_intent",
    "description": "Classify the user's message into a known intent.",
    "input_schema": {
        "type": "object",
        "properties": {
            "intent": {
                "type": "string",
                "enum": ["create_task", "update_task", "delete_task", "list_tasks", "unknown"],
            },
            "entity_id": {"type": "string", "description": "Task ID if applicable"},
            "parameters": {
                "type": "object",
                "description": "Extracted key-value parameters for the intent",
            },
        },
        "required": ["intent", "parameters"],
    },
}

def extract_intent(user_message: str) -> IntentSchema:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        tools=[INTENT_TOOL],
        tool_choice={"type": "any"},
        messages=[{"role": "user", "content": user_message}],
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "classify_intent":
            return IntentSchema(**block.input)
    return IntentSchema(intent="unknown", parameters={})
